        for (char c : s.toCharArray()) cnt[c - '0']++;
        StringBuilder sb = new StringBuilder();
        if (neg) {
            for (int d = 9; d >= 0; --d) {
                while (cnt[d]-- > 0) sb.append((char)('0' + d));
            }
        } else {
            int first = 1;
            while (first < 10 && cnt[first] == 0) first++;
            if (first < 10) {
                sb.append((char)('0' + first));
                cnt[first]--;
            }
            for (int d = 0; d < 10; ++d) {
                while (cnt[d]-- > 0) sb.append,"
                    (char)('0' + d));
            }
        }
        long res = Long.parseLong(sb.toString());
        return neg ? -res : res;
    }
